import{_ as e,c as l,o as i,a3 as c}from"./chunks/framework.CswI76e5.js";const a="/assets/fig-1.SY2GU9zW.png",d="/assets/fig-2.CES0TiAH.png",m=JSON.parse('{"title":"2.2 作業環境の構築","description":"","frontmatter":{},"headers":[],"relativePath":"cpp/chapter-2/2.md","filePath":"cpp/chapter-2/2.md","lastUpdated":1778209237000}'),t={name:"cpp/chapter-2/2.md"};function r(s,o,n,p,h,u){return i(),l("div",null,o[0]||(o[0]=[c('<h1 id="_2-2-作業環境の構築" tabindex="-1">2.2 作業環境の構築 <a class="header-anchor" href="#_2-2-作業環境の構築" aria-label="Permalink to &quot;2.2 作業環境の構築&quot;">​</a></h1><p>ここからは実際に手を動かして、作業するための場所を作っていこう。</p><h2 id="_2-2-1-はじめてのターミナル" tabindex="-1">2.2.1 はじめてのターミナル <a class="header-anchor" href="#_2-2-1-はじめてのターミナル" aria-label="Permalink to &quot;2.2.1 はじめてのターミナル&quot;">​</a></h2><p>まずはターミナルを開いてみよう。黒い画面に白い文字（Macでは白い画面に黒い文字）が出ていて、ここにコマンドを打ち込むことでコンピューターを直接操作することができる。 試しに<code>echo &quot;Hello&quot;</code>と打ち込んで改行すると、<code>Hello</code>が出力される。<code>echo</code>は、次に与えられた文字列をそのまま出力するコマンドである。</p><p>Windowsにおいては、WSLのターミナルを用いてLinuxを操作することができ、Macにおいてはターミナルを用いてコンピューターを操作することができる。 Windowsの環境構築で少し出てきた「PowerShell」はWindowsを操作するイメージ。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>echo</code>は「こだま・反響」</p></div><ol><li>「ターミナル」を起動する。</li><li><code>echo &quot;Hello&quot;</code>と入力する。</li><li><code>Hello</code> という行が表示されていればOK。</li></ol><p><img src="https://md.trap.jp/uploads/upload_8550a6882b611e212c99ef7b78187cb6.png" alt=""></p><p>自分の画面とはおそらく違うだろうが、概ねこのような風に<code>Hello</code>が表示されれば問題ない。</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>行の冒頭にユーザー名や端末名などが表示されますが、問題ありません。そのままコマンドを入力してください。</p></div><h2 id="_2-2-2-ディレクトリとは" tabindex="-1">2.2.2 ディレクトリとは <a class="header-anchor" href="#_2-2-2-ディレクトリとは" aria-label="Permalink to &quot;2.2.2 ディレクトリとは&quot;">​</a></h2><p>ディレクトリは、エクスプローラー（Windows）/Finder（Mac）で「フォルダ」に相当するものである。ターミナルは<strong>常にどこかのディレクトリ上に居るものとして振る舞う。</strong> エクスプローラー/Finderと見比べながら、コマンドを打ち込んで理解しよう。</p><h3 id="ターミナルでの操作" tabindex="-1">ターミナルでの操作 <a class="header-anchor" href="#ターミナルでの操作" aria-label="Permalink to &quot;ターミナルでの操作&quot;">​</a></h3><ol><li>ターミナルを開く。</li><li>ターミナルで<code>pwd</code>と打つと、現在の自分の場所がわかる。</li><li>ターミナルで<code>ls</code>と打つと、今居るディレクトリにあるファイル一覧が表示される。（最初はほぼないはず！）</li></ol><h4 id="エクスプローラー-windows" tabindex="-1">エクスプローラー（Windows） <a class="header-anchor" href="#エクスプローラー-windows" aria-label="Permalink to &quot;エクスプローラー（Windows）&quot;">​</a></h4><p>エクスプローラーを起動すると、自分のコンピューターに保存されているファイルを一覧することができる。</p><ol><li>エクスプローラーを開く。</li><li>エクスプローラーの「表示」をクリックする。 <img src="'+a+'" alt=""></li><li>「ファイル名拡張子」にチェックを入れる。</li><li>サイドバーに「Linux」があるので、それをダブルクリックする。 <img src="'+d+'" alt=""></li><li>「Ubuntu」をクリックする。</li><li><code>pwd</code>コマンドの結果を見ながら、「home」→「（自分の名前）」でアクセスする。</li></ol><h4 id="finder-mac" tabindex="-1">Finder（Mac） <a class="header-anchor" href="#finder-mac" aria-label="Permalink to &quot;Finder（Mac）&quot;">​</a></h4><p>Finderを起動すると、自分のコンピューターに保存されているファイルを一覧することができる。</p><ol><li>Finderを開く。</li><li>Finderで<code>⌘</code>+<code>,</code>を押す。</li><li>「詳細」→「すべてのファイル名拡張子を表示」をONにする。</li><li>Finderで<code>⌘</code>+<code>Shift</code>+<code>G</code>を押す。</li><li><code>pwd</code>で出てきたテキストをそのまま入力する。</li></ol><h2 id="_2-2-3-作業環境の構築" tabindex="-1">2.2.3 作業環境の構築 <a class="header-anchor" href="#_2-2-3-作業環境の構築" aria-label="Permalink to &quot;2.2.3 作業環境の構築&quot;">​</a></h2><h3 id="コマンド紹介" tabindex="-1">コマンド紹介 <a class="header-anchor" href="#コマンド紹介" aria-label="Permalink to &quot;コマンド紹介&quot;">​</a></h3><ul><li><code>pwd</code>：現在の自分の場所を表示する。 (<strong>P</strong>rint <strong>W</strong>orking <strong>D</strong>irectory)</li><li><code>ls</code>：今居るディレクトリにあるファイルの一覧を表示する。 (<strong>l</strong>i<strong>s</strong>t)</li><li><code>cd {path}</code>：<code>{path}</code>に移動したいディレクトリを入れることで、今居るディレクトリから<code>{path}</code>のディレクトリへ移動する。 (<strong>C</strong>hange <strong>D</strong>irectory) <ul><li>例えば、<code>cd abc</code>と打つと、今居るディレクトリの下にある、<code>abc</code>という名前のディレクトリに移動する。</li></ul></li><li><code>cd ../</code>：一つ親のディレクトリに移動する <ul><li>例えば、今居るディレクトリが<code>/home/traP</code>なら<code>/home</code>に移動に移動する。</li></ul></li><li><code>mkdir {path}</code>：ディレクトリを作成する (<strong>M</strong>a<strong>k</strong>e <strong>Dir</strong>ectory)</li></ul><h3 id="作業環境の作成" tabindex="-1">作業環境の作成 <a class="header-anchor" href="#作業環境の作成" aria-label="Permalink to &quot;作業環境の作成&quot;">​</a></h3><p>まずは、ターミナルでコマンドを打ち、作業するための場所を作成しよう。</p><ol><li>ターミナルで<code>cd ~</code>と入力する。（<code>~</code>は<code>0</code>の2つ右のキー<code>^</code>+<code>Shift</code>を同時押し） <ul><li>ホームディレクトリに移動できる。</li></ul></li><li>ターミナルで<code>mkdir pgbasic</code>と入力する。 <ul><li><code>pgbasic</code>というディレクトリが作られる。</li></ul></li></ol><h3 id="作業環境を開く" tabindex="-1">作業環境を開く <a class="header-anchor" href="#作業環境を開く" aria-label="Permalink to &quot;作業環境を開く&quot;">​</a></h3><p>次に、上で作った作業環境をVSCodeで開こう。</p><ol><li>ターミナルで<code>cd pgbasic</code>と入力する。 <ul><li><code>pgbasic</code>のディレクトリに移動する。</li></ul></li><li>ターミナルで<code>pwd</code>と入力する。 <ul><li>今いるディレクトリの場所が出力される。最後が<code>/pgbasic</code>で終わっていればOK！</li></ul></li><li><code>code main.cpp</code><ul><li>VSCodeを開く。ここが講習中の作業場所。</li></ul></li></ol><p>もしくは、VSCodeを直接起動しても前回のファイル・ディレクトリを開けるようになる。</p>',30)]))}const b=e(t,[["render",r]]);export{m as __pageData,b as default};
